const OuroborosRing = memo(forwardRef(function OuroborosRing({ size = 500 }, ref) {
  const svgRef  = useRef(null)
  const glowRef = useRef(null)
  const scoreRef = useRef(0)
  const frameRef = useRef(null)

  useImperativeHandle(ref, () => ({
    setScore(n) { scoreRef.current = Math.max(0, Math.min(10, n)) },
  }), [])

  useEffect(() => {
    const startTime = performance.now()

    function loop(now) {
      const t     = (now - startTime) / 1000
      const score = scoreRef.current

      // 4-wave composite pulse
      const pulse =
        Math.sin(t * 1.2)  * 0.38 +
        Math.sin(t * 2.6)  * 0.27 +
        Math.sin(t * 0.75) * 0.22 +
        Math.sin(t * 4.1)  * 0.13
      const normPulse = pulse / (0.38 + 0.27 + 0.22 + 0.13)
      const range  = 0.025 + (score / 10) * 0.06
      const scale  = 1 + normPulse * range

      // brightness flicker
      const brightness = 0.82 + 0.16 * Math.sin(t * 3.3) + 0.04 * Math.sin(t * 7.1)

      // edge blur increases with danger
      const blurPx = score > 5 ? ((score - 5) / 5) * Math.abs(normPulse) * 10 : 0

      const color = scoreToColor(score)
      const [r, g, b] = color.match(/\d+/g).map(Number)
      const glowAlpha = 0.05 + (score / 10) * 0.28 + Math.abs(normPulse) * 0.06

      if (svgRef.current) {
        svgRef.current.style.color = color
        svgRef.current.style.transform = `scale(${scale.toFixed(4)})`
        const filterParts = [`brightness(${brightness.toFixed(3)})`]
        if (blurPx > 0.3) filterParts.unshift(`blur(${blurPx.toFixed(1)}px)`)
        svgRef.current.style.filter = filterParts.join(' ')
      }

      if (glowRef.current) {
        glowRef.current.style.background =
          `radial-gradient(ellipse at center, rgba(${r},${g},${b},${glowAlpha.toFixed(3)}) 25%, transparent 72%)`
      }

      frameRef.current = requestAnimationFrame(loop)
    }

    frameRef.current = requestAnimationFrame(loop)
    return () => cancelAnimationFrame(frameRef.current)
  }, []) // empty — never restarts

  return (
    <div style={{ width: size, height: size, position: 'relative', flexShrink: 0 }}>
      {/* glow haze behind the shape */}
      <div
        ref={glowRef}
        style={{
          position: 'absolute',
          inset: '-25%',
          borderRadius: '50%',
          pointerEvents: 'none',
        }}
      />
      {/* inline SVG — no mask, no URL, perfect centering */}
      <svg
        ref={svgRef}
        viewBox="80 -20 510 510"
        preserveAspectRatio="xMidYMid meet"
        style={{
          width: '100%',
          height: '100%',
          display: 'block',
          color: '#f0ede8',
          transformOrigin: 'center center',
          overflow: 'visible',
        }}
      >
        <path fill="currentColor" d={PATH_D} />
      </svg>
    </div>
  )
}))

export default OuroborosRing
